INSERT IGNORE INTO `pertanyaan_identifikasi` (`id`, `sub_kategori_id`, `ruang_lingkup_id`, `pertanyaan_identifikasi`, `index0`, `index1`, `index2`, `index3`, `index4`, `index5`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'Pimpinan organisasi menetapkan keamanan siber sebagai prioritas di organisasi dalam bentuk kebijakan atau komitmen pimpinan yang sesuai dengan kondisi bisnis/layanan dan operasional organisasi.', 'Belum ada penerapan kebijakan atau komitmen pimpinan terkait keamanan siber.', 'Kebijakan Keamanan Siber diterapkan pada sebagian kecil aspek, namun belum ditetapkan secara formal', 'Kebijakan Keamanan Siber diterapkan pada sebagian besar aspek, namun belum ditetapkan secara formal', '- Kebijakan terkait keamanan siber telah disusun dan ditetapkan\r\n- Pimpinan berkomitmen untuk memasukkan keamanan siber sebagai prioritas organisasi.', '- Kebijakan terkait keamanan siber telah disusun, ditetapkan, dimonitor, dan dilakukan review secara berkala\r\n- Pimpinan berkomitmen untuk memasukkan keamanan siber sebagai prioritas organisasi.', '- Kebijakan terkait keamanan siber telah disusun, ditetapkan, dimonitor, dan dilakukan review serta pembaruan secara berkala - Pimpinan berkomitmen untuk memasukkan keamanan siber sebagai prioritas organisasi.', '2026-03-11 06:49:00', '2026-03-30 03:14:27'),
(2, 1, 1, 'Penyelenggara Sistem Elektronik mengomunikasikan perihal komitmen keamanan siber di organisasinya dengan pihak-pihak yang terkait dengan bisnis/layanan organisasi (termasuk kepada penyedia pihak ketiga).', 'Komitmen dan kebijakan keamanan siber yang harus dipatuhi pihak terkait belum dikomunikasikan', 'Kebijakan keamanan siber yang harus dipatuhi pihak terkait sudah dikomunikasikan pada sebagian kecil aspek, namun belum ditetapkan secara formal', 'Kebijakan keamanan siber yang harus dipatuhi pihak terkait sudah dikomunikasikan pada sebagian besar aspek, namun belum ditetapkan secara formal', 'Kebijakan keamanan siber yang harus dipatuhi pihak terkait sudah dikomunikasikan pada seluruh aspek dan sudah ditetapkan secara formal', 'Kebijakan keamanan siber yang harus dipatuhi pihak terkait sudah dikomunikasikan pada seluruh aspek dan sudah ditetapkan secara formal, dimonitor, dan dilakukan review secara berkala', 'Kebijakan keamanan siber yang harus dipatuhi pihak terkait sudah dikomunikasikan pada seluruh aspek dan sudah ditetapkan secara formal, dimonitor, dan dilakukan review secara berkala, dan dilakukan perbaikan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(3, 2, 1, 'Penyelenggara Sistem Elektronik mengidentifikasi unit kerja di internal organisasinya, maupun pihak lain di luar organisasinya yang memiliki ketergantungan, baik secara langsung maupun tidak langsung terhadap operasional layanan Sistem Elektronik di organisasinya.', '- Belum dilakukan identifikasi unit kerja maupun pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya\r\n- Belum ada prosedur identifikasi ketergantungan', '- Organisasi mengetahui sebagian kecil unit kerja maupun pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya, namun prosedur identifikasi ketergantungan belum ditetapkan secara formal', '- Organisasi mengetahui sebagian besar unit kerja maupun pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya, namun prosedur identifikasi ketergantungan belum ditetapkan secara formal', '- Identifikasi unit kerja maupun pihak lain yang bergantung pada layanan SE di organisasinya telah dilakukan secara menyeluruh\r\n- Prosedur identifikasi ketergantungan sudah ditetapkan.', '- Identifikasi unit kerja maupun pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya telah dilakukan\r\n- Prosedur identifikasi ketergantungan sudah ditetapkan dan dievaluasi secara berkala\r\n- Daftar unit kerja atau pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya dimonitor dan dievaluasi secara berkala\r\n- Belum ada mekanisme/siklus pembaruan daftar unit kerja atau pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya', '- Identifikasi unit kerja maupun pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya telah dilakukan\r\n- Prosedur identifikasi ketergantungan sudah ditetapkan dan dievaluasi serta diperbarui secara berkala\r\n- Sudah ada mekanisme/siklus pembaruan daftar unit kerja atau pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya\r\n- Daftar unit kerja atau pihak lain yang bergantung pada layanan Sistem Elektronik di organisasinya dimonitor, dievaluasi, dan diperbarui secara berkala\r\n', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(4, 3, 1, 'Penyelenggara Sistem Elektronik mengidentifikasi dan menetapkan unit kerja atau fungsi yang memiliki tugas dan tanggung jawab dalam menerapkan pengamanan Sistem Elektronik di organisasinya.', 'Belum adanya rencana terkait identifikasi unit kerja atau fungsi yang memiliki tugas dan tanggung jawab dalam menerapkan pengamanan Sistem Elektronik di organisasinya.', 'Sudah terdapat unit kerja yang menerapkan sebagian kecil fungsi pengamanan Sistem Elektronik di organisasinya, namun belum ditetapkan tugas dan tanggung jawab secara formal', 'Sudah terdapat unit kerja yang menerapkan sebagian besar fungsi pengamanan Sistem Elektronik di organisasinya, namun belum ditetapkan tugas dan tanggung jawab secara formal', 'Seluruh fungsi dalam menerapkan pengamanan Sistem Elektronik telah diidentifikasi dan unit kerja yang memiliki tugas dan tanggung jawab dalam menerapkan pengamanan Sistem Elektronik di organisasinya telah ditetapkan. ', '- Seluruh fungsi dalam menerapkan penyelenggaraan SE telah diidentifikasi dan unit kerja yang memiliki tugas dan tanggung jawab dalam menerapkan pengamanan Sistem Elektronik di organisasinya telah ditetapkan. \r\n- Dilakukan evaluasi berkala terhadap fungsi, tugas, dan tanggung jawab unit kerja tersebut dalam menerapkan pengamanan Sistem Elektronik agar tetap inline dengan tujuan organisasi.', '- Seluruh fungsi dalam menerapkan penyelenggaraan SE telah diidentifikasi dan unit kerja yang memiliki tugas dan tanggung jawab dalam menerapkan pengamanan Sistem Elektronik di organisasinya telah ditetapkan. \r\n- Dilakukan evaluasi berkala terhadap fungsi, tugas, dan tanggung jawab unit kerja tersebut dalam menerapkan pengamanan Sistem Elektronik agar tetap inline dengan tujuan organisasi.\r\n- Dilakukan perbaikan berkelanjutan untuk memastikan proses binis yang dijalankan oleh unit kerja tersebut tetap efektif dan sesuai dengan kebutuhan dan kondisi terkini.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(5, 3, 1, 'Penyelenggara Sistem Elektronik mengidentifikasi peran, aktivitas, proses, dan narahubung dari pemangku kepentingan yang mendukung ekosistem bisnis atau layanan Sistem Elektronik, baik di dalam atau di luar organisasi.', 'Peran, aktivitas, proses, dan narahubung pemangku kepentingan belum diidentifikasi.', 'Organisasi mengetahui sebagian kecil peran, aktivitas, proses, dan narahubung pemangku kepentingan namun belum ditetapkan secara formal', 'Organisasi mengetahui sebagian besar peran, aktivitas, proses, dan narahubung pemangku kepentingan namun belum ditetapkan secara formal', 'Peran, aktivitas, proses, dan narahubung pemangku kepentingan telah diidentifikasi dan ditetapkan dalam sebuah dokumen formal.', '- Peran, aktivitas, proses, dan narahubung pemangku kepentingan telah diidentifikasi dan ditetapkan dalam sebuah dokumen formal.\r\n- Penetapan peran, aktivitas, proses, dan narahubung pemangku kepentingan dimonitor dan dievaluasi secara berkala.', '- Peran, aktivitas, proses, dan narahubung pemangku kepentingan telah diidentifikasi dan ditetapkan dalam sebuah dokumen formal.\r\n- Penetapan peran, aktivitas, proses, dan narahubung pemangku kepentingan dimonitor dan dievaluasi secara berkala.\r\n- Dilakukan pembaruan secara berkala terhadap penetapan peran, aktivitas, proses, dan narahubung pemangku kepentingan sebagai timbal balik dari evaluasi yang dilakukan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(6, 4, 1, 'Penyelenggara Sistem Elektronik menyusun, menetapkan, dan mengembangkan kebijakan tentang keamanan siber sesuai dengan standar yang berlaku di sektornya dan/atau peraturan perundang-undangan', 'Organisasi belum memiliki kebijakan tentang keamanan siber sesuai dengan standar yang berlaku di sektornya dan/atau peraturan perundang-undangan.', 'Organisasi telah menyusun kebijakan tentang keamanan siber sesuai dengan standar yang berlaku di sektornya dan/atau peraturan perundang undangan dan sudah menerapkan pada sebagian kecil aspek, namun kebijakan tersebut belum ditetapkan.', 'Organisasi telah  menerapkan kebijakan keamanan siber pada sebagian besar aspek sesuai dengan standar yang berlaku di sektornya dan/atau peraturan perundang-undangan namun kebijakan tersebut belum ditetapkan.\r\n', 'Organisasi tidak hanya telah menerapkan, tetapi juga telah menetapkan kebijakan keamanan siber sesuai dengan standar yang berlaku di sektornya dan/atau peraturan perundang-undangan.', '- Organisasi tidak hanya telah menerapkan dan menetapkan kebijakan keamanan siber, tetapi juga secara aktif mengelola dan meninjau kebijakan ini untuk memastikan bahwa mereka tetap relevan dan efektif. \r\n\r\n- Dilakukannya proses peninjauan dan pembaruan kebijakan yang terstruktur.', '- Organisasi telah berhasil menyusun, menetapkan, dan mengembangkan kebijakan keamanan siber yang komprehensif dan efektif yang sepenuhnya sesuai dengan standar dan regulasi yang berlaku. \r\n\r\n- Kebijakan tersebut dikelola dan ditinjau secara berkala, dan ada mekanisme umpan balik serta perbaikan berkelanjutan untuk memastikan bahwa kebijakan ini tetap relevan dan efektif.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(7, 4, 1, 'Penyelenggara Sistem Elektronik mengomunikasikan kebijakan kepada seluruh personel yang relevan, serta mengoordinasikan dan menyepakati metode berbagi informasi mengenai kebijakan dan prosedur yang ada di organisasi dengan para pemangku kepentingan eksternal.', 'Organisasi  belum mengomunikasikan dan mengoordinasikan kebijakan dan prosedur dengan personel dan pemangku kepentingan eksternal, dan belum memiliki mekanisme komunikasi terkait hal tersebut.', 'Organisasi mulai mengomunikasikan dan mengoodinasikan kebijakan dan prosedur kepada sebagian kecil personel dan pemangku kepentingan eksternal, namun mekanisme komunikasi tersebut belum ditetapkan.', 'Organisasi telah mengomunikasikan dan mengoodinasikan kebijakan dan prosedur kepada sebagian besar personel dan pemangku kepentingan eksternal, namun mekanisme komunikasi tersebut belum ditetapkan.', 'Organisasi mengomunikasikan kebijakan kepada seluruh personel yang relevan, serta mengoordinasikan dan menyepakati metode berbagi informasi mengenai kebijakan dan prosedur yang ada di organisasi dengan para pemangku kepentingan eksternal secara efektif dan efisien.', '- Organisasi mengomunikasikan kebijakan kepada seluruh personel yang relevan, serta mengoordinasikan dan menyepakati metode berbagi informasi mengenai kebijakan dan prosedur yang ada di organisasi dengan para pemangku kepentingan eksternal secara efektif dan efisien.\r\n\r\n\r\n- Mekanisme komunikasi, koordinasi kebijakan dan prosedur dengan personel dan pemangku kepentingan eksternal yang telah disusun,  dikelola dan ditinjau efektivitasnya secara berkala.', '- Organisasi mengomunikasikan kebijakan kepada seluruh personel yang relevan, serta mengoordinasikan dan menyepakati metode berbagi informasi mengenai kebijakan dan prosedur yang ada di organisasi dengan para pemangku kepentingan eksternal secara efektif dan efisien.\r\n\r\n- Mekanisme komunikasi, koordinasi kebijakan dan prosedur dengan personel dan pemangku kepentingan eksternal yang telah disusun,  dikelola dan ditinjau efektivitasnya secara berkala dan ada mekanisme umpan balik serta perbaikan berkelanjutan untuk memastikan bahwa kebijakan ini tetap relevan dan efektif.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(8, 4, 1, 'Penyelenggara Sistem Elektronik meninjau dan merevisi kebijakannya secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya.', 'Penyelenggara belum memiliki rencana untuk meninjau dan merevisi kebijakannya secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya', 'Peninjauan dan revisi mulai dilakukan terhadap penerapan kebijakan pada sebagian kecil aspek secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya, namun mekanisme tersebut belum ditetapkan.', 'Peninjauan dan revisi terhadap penerapan kebijakan pada sebagian besar aspek  secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya, telah dilaksanakan namun mekanisme tersebut belum ditetapkan.', 'Peninjauan dan revisi kebijakan yang telah diterapkan pada seluruh aspek secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya, telah dilaksanakan secara menyeluruh dan telah ditetapkan mekanismenya.', 'Peninjauan dan revisi kebijakan  yang telah diterapkan pada seluruh aspek secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya, telah dilaksanakan secara menyeluruh dan  secara aktif mengelola dan meninjau efektivitasnya.', 'Peninjauan dan revisi kebijakan  yang telah diterapkan pada seluruh aspek secara berkelanjutan sesuai dengan setiap perubahan dalam peraturan perundang-undangan yang relevan, standar dan/atau pedoman industri yang berlaku di sektornya, telah dilaksanakan secara menyeluruh dan secara aktif mengelola dan meninjau efektivitasnya serta terdapat mekanisme perbaikan berkelanjutan untuk memastikan bahwa kebijakan ini tetap relevan dan efektif.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(9, 5, 1, 'Penyelenggara Sistem Elektronik senantiasa mengembangkan strategi dalam melindungi aset informasi dengan mempertimbangkan manajemen risiko yang berlaku di organisasi.', 'Organisasi Belum memiliki strategi perlindungan aset informasi dan\r\nbelum memiliki dokumen manajemen risiko organisasi', 'Prosedur pengamanan aset informasi, manajemen risiko organisasi dan Strategi pengamanan aset informasi  sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Prosedur pengamanan aset informasi, manajemen risiko organisasi dan Strategi pengamanan aset informasi  sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', 'Prosedur pengamanan aset informasi, manajemen risiko organisasi dan Strategi pengamanan aset informasi  sudah diterapkan pada seluruh aspek dan sudah diformalkan', 'Prosedur pengamanan aset informasi, manajemen risiko organisasi dan Strategi pengamanan aset informasi  sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring dan reviu secara berkala ', 'Prosedur pengamanan aset informasi, manajemen risiko organisasi dan Strategi pengamanan aset informasi  sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring dan reviu secara berkala, dilakukan perbaikan berkelanjutan dan terintegrasi dalam sistem yang terotomatisasi.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(10, 5, 1, 'Penyelenggara Sistem Elektronik harus menetapkan sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan.', 'Organisasi belum memiliki sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan.', 'Sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan telah dijalankan pada sebagian kecil aspek namun belum ditetapkan.', 'Sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan telah dijalankan pada sebagian besar aspek namun belum ditetapkan.', 'Sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan telah ditetapkan dan dijalankan secara menyeluruh.', 'Sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan telah ditetapkan dan dijalankan secara menyeluruh, dilakukan monitoring dan direview secara berkala.', 'Sasaran atau target penerapan keamanan siber pada fungsi dan tingkatan yang relevan telah dtetapkan dan dijalankan secara menyeluruh, dilakukan monitoring dan direview secara berkala serta dievaluasi dan dilakukan perbaikan berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(11, 6, 1, 'Penyelenggara Sistem Elektronik menyusun kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber.', 'Organisasi belum memiliki Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber.', 'Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber sudah diterapkan pada sebagian kecil aspek namun belum ditetapkan.', 'Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber sudah diterapkan pada sebagian besar aspek namun belum ditetapkan.', 'Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber sudah diterapkan pada seluruh aspek dan sudah ditetapkan.', 'Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber sudah diterapkan pada seluruh aspek dan sudah ditetapkan, dilakukan monitoring dan direview secara berkala.', 'Kebijakan standar operasional prosedur terhadap setiap layanan yang mendukung Sistem Elektronik baik dalam kondisi normal, jika terjadi insiden siber, dan pasca insiden siber sudah diterapkan pada seluruh aspek dan sudah ditetapkan, dilakukan monitoring dan direview secara berkala serta dievaluasi dan dilakukan perbaikan berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(12, 7, 1, 'Penyelenggara Sistem Elektronik menyusun kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi, dsb.', 'Organisasi belum menyusun kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi, dsb', 'Kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi sudah diterapkan pada sebagian kecil aspek, namun belum ditetapkan.', 'Kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi sudah diterapkan pada sebagian besar aspek, namun belum ditetapkan.', 'Kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi sudah diterapkan pada seluruh aspek dan sudah ditetapkan.', 'Kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi sudah diterapkan pada seluruh aspek dan sudah ditetapkan, dilakukan monitoring dan direview secara berkala.', 'Kebijakan yang diperlukan untuk menjaga ketersediaan aset informasi, seperti kebijakan penggunaan perangkat pribadi di kantor (bring your own devices), kebijakan instalasi perangkat lunak pada perangkat kantor, kebijakan klasifikasi informasi sudah diterapkan pada seluruh aspek dan sudah ditetapkan, dilakukan monitoring dan direview secara berkala serta dievaluasi dan dilakukan perbaikan berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(13, 8, 4, 'Dokumentasikan dan kelola dengan tepat daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb).', 'Organisasi belum menyusun daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb), belum mendokumentasikan dan mengelolanya.', 'Organisasi telah melakukan dokumentasi dan pengelolaan pada sebagian kecil daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb) namun belum diformalkan', 'Organisasi telah melakukan dokumentasi dan pengelolaan pada sebagian besar daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb) namun belum diformalkan', 'Organisasi telah melakukan dokumentasi dan pengelolaan pada seluruh daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb) dan sudah diformalkan', 'Organisasi telah melakukan dokumentasi dan pengelolaan pada seluruh daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb) dan sudah diformalkan, dilakukan monitoring dan direview secara berkala', 'Organisasi telah melakukan dokumentasi dan pengelolaan pada seluruh daftar inventaris aset informasi seperti perangkat keras, perangkat lunak, data, dan layanan TIK yang akan dilindungi,  beserta informasi manajemennya (misalnya nama aset, versi, alamat jaringan, nama penanggungjawab, informasi lisensi, dsb) dan sudah diformalkan, dilakukan monitoring dan direview secara berkala serta dievaluasi dan dilakukan perbaikan berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(14, 8, 1, 'Penyelenggara Sistem Elektronik memastikan pemberian label pada perangkat aset informasi oleh pihak yang berwenang di organisasi', 'Organisasi belum memiliki prosedur dan belum memastikan pemberian label pada perangkat aset informasi oleh pihak yang berwenang di organisasi  ', 'Organisasi telah menerapkan prosedur pemberian label pada sebagian kecil aspek perangkat aset informasi oleh pihak yang berwenang di organisasi dan belum diformalkan', 'Organisasi telah menerapkan prosedur pemberian label pada sebagian besar aspek perangkat aset informasi oleh pihak yang berwenang di organisasi namun belum diformalkan', 'Organisasi telah menerapkan prosedur pemberian label pada seluruh aspek perangkat aset informasi oleh pihak yang berwenang di organisasi dan sudah diformalkan', 'Organisasi telah menerapkan prosedur pemberian label pada seluruh aspek perangkat aset informasi oleh pihak yang berwenang di organisasi dan sudah diformalkan, dilakukan monitoring dan direview secara berkala.', 'Organisasi telah menerapkan prosedur pemberian label pada seluruh aspek perangkat aset informasi oleh pihak yang berwenang di organisasi dan sudah diformalkan, dilakukan monitoring dan direview secara berkala, serta dievaluasi dan dilakukan perbaikan berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(15, 9, 2, 'Penyelenggara Sistem Elektronik menyusun dokumentasi dan mengelola diagram jalur komunikasi jaringan dan aliran data dengan tepat dalam organisasi.', '- Organisasi belum dapat menunjukan dokumentasi diagram jalur komunikasi jaringan (network architecture) dan aliran data (document data flow) yang berhubungan dengan layanan Sistem Elektronik.\r\n- Organisasi belum dapat menunjukan bahwa jalur komunikasi jaringan dan aliran data yang berhubungan dengan layanan Sistem Elektronik telah dikelola sesuai dengan persyaratan keamanan.', 'Organisasi telah menyusun dokumentasi diagram jalur komunikasi jaringan dan aliran data dalam bentuk rancangan, atau dokumen diagram jalur komunikasi jaringan dan aliran data, namun baru diterapkan pada sebagian kecil aspek dan belum diformalkan', 'Organisasi telah menyusun dokumentasi diagram jalur komunikasi jaringan dan aliran data dalam bentuk rancangan, atau dokumen diagram jalur komunikasi jaringan dan aliran data, namun baru diterapkan pada sebagian besar aspek dan belum diformalkan', 'Organisasi telah menyusun dokumentasi diagram jalur komunikasi jaringan dan aliran data dalam bentuk rancangan, atau dokumen diagram jalur komunikasi jaringan dan aliran data, sudah diterapkan pada seluruh aspek dan sudah diformalkan', 'Organisasi telah menyusun dokumentasi diagram jalur komunikasi jaringan dan aliran data dalam bentuk rancangan, atau dokumen diagram jalur komunikasi jaringan dan aliran data, sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring dan direview secara berkala', 'Organisasi telah menyusun dokumentasi diagram jalur komunikasi jaringan dan aliran data dalam bentuk rancangan, atau dokumen diagram jalur komunikasi jaringan dan aliran data, sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring dan direview secara berkala, dilakukan evaluasi dan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(16, 10, 1, 'Dokumentasikan dan kelola dengan tepat daftar sistem informasi eksternal yang menggunakan data atau layanan Sistem Elektronik', 'Organisasi belum memiliki daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan Sistem Elektronik', 'Organisasi telah melaksanakan dokumentasi dan pengelolaan terhadap sebagian kecil aspek dari daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan Sistem Elektronik namun belum diformalkan', 'Organisasi telah melaksanakan dokumentasi dan pengelolaan terhadap sebagian besar daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan Sistem Elektronik namun belum diformalkan', 'Organisasi telah melaksanakan dokumentasi dan pengelolaan terhadap seluruh daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan Sistem Elektronik dan sudah diformalkan', 'Organisasi telah melaksanakan dokumentasi dan pengelolaan terhadap seluruh daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan IIV dan sudah diformalkan, dilakukan monitoring dan direview secara berkala', 'Organisasi telah melaksanakan dokumentasi dan pengelolaan terhadap seluruh daftar sistem informasi stakeholder dan pihak eksternal yang menggunakan data atau layanan Sistem Elektronik dan sudah diformalkan, dilakukan monitoring dan direview secara berkala, dievaluasi dan dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
